module top_module(clk, rst, en, out);input clk, rst, en;
    output [3:0] out;

    reg [3:0] unused_count;

    always @(posedge clk or posedge rst)
    begin
        if (rst)
            unused_count <= 4'd0;
        else if (en)
            unused_count <= unused_count + 1;
    end

    assign out = unused_count;
endmodule
